appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const pathData = rawData.paths || {};
    const crossFileData = rawData.cross_file || {};
    const nodes = pathData.nodes || [];

    // =====================================================================
    // CONFIG — presentation only (badge colors have no data source).
    // Context label, severity and data context all come from the node itself.
    // =====================================================================
    const CONFIG = {
      badgeBySensitivity: {
        critical: 'badge-critical',
        high: 'badge-warning',
        medium: 'badge-warning',
        low: 'badge-safe',
        unknown: 'badge-safe'
      },
      badgeDefault: 'badge-safe',
      // Sort order: most sensitive first.
      sensitivityOrder: {
        critical: 0,
        high: 1,
        medium: 2,
        low: 3,
        unknown: 4
      },
      snippetLen: 50,
      locationColor: '#7f8c8d',
      emptyTable: 'No active exposure paths detected in this scan.'
    };

    // snake_case -> label, acronym-aware: llm_call -> "LLM Call", db_write -> "DB Write"
    const fmtType = t => String(t || '').split('_').map(w => w.length <= 3 ? w.toUpperCase() : w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    const cap = s => s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : s;
    const sensRank = s => CONFIG.sensitivityOrder[String(s || 'unknown').toLowerCase()] ?? 99;

    // --- 1. Summary Metrics (wired to the scan) -------------------------
    document.getElementById('flow-nodes').innerText = nodes.length;
    document.getElementById('boundary-crossings').innerText = crossFileData.ai_boundaries || 0;
    document.getElementById('tainted-symbols').innerText = crossFileData.tainted_symbols || 0;

    // --- 2. Sort by the scanner's real sensitivity ----------------------
    // Ties: nodes carrying concrete data_types surface above bare ones.
    const sortedNodes = nodes.slice().sort((a, b) => {
      const d = sensRank(a.sensitivity) - sensRank(b.sensitivity);
      if (d !== 0) return d;
      const ad = (a.data_types || []).length ? 0 : 1;
      const bd = (b.data_types || []).length ? 0 : 1;
      return ad - bd;
    });

    // --- 3. Populate Exposure Path table --------------------------------
    const tbody = document.getElementById('path-table-body');
    tbody.innerHTML = '';
    if (sortedNodes.length === 0) {
      tbody.innerHTML = `<tr><td colspan="4" style="text-align: center;">${CONFIG.emptyTable}</td></tr>`;
      return;
    }
    sortedNodes.forEach(node => {
      const parts = String(node.type || '').split('.');
      const stage = (parts[0] || '').toUpperCase(); // SOURCE / TRANSFORM / SINK / AI
      const subtype = parts.slice(1).join('.') || parts[0]; // e.g. llm_call, log, db_write
      const sensitivity = String(node.sensitivity || 'unknown').toLowerCase();
      const dataTypes = node.data_types || [];
      const badgeClass = CONFIG.badgeBySensitivity[sensitivity] || CONFIG.badgeDefault;
      const tr = document.createElement('tr');

      // Flow Stage
      const tdType = document.createElement('td');
      const strong = document.createElement('strong');
      strong.textContent = stage;
      tdType.appendChild(strong);

      // Component Name
      const tdName = document.createElement('td');
      const codeName = document.createElement('code');
      codeName.textContent = node.name || '';
      tdName.appendChild(codeName);

      // Boundary & Data Context — real subtype (colored by real sensitivity),
      // real sensitive data_types, then a code snippet as evidence.
      const tdContext = document.createElement('td');
      const badge = document.createElement('span');
      badge.className = `badge ${badgeClass}`;
      badge.textContent = fmtType(subtype);
      tdContext.appendChild(badge);
      if (dataTypes.length > 0) {
        const data = document.createElement('span');
        data.className = 'evidence';
        data.textContent = `${cap(sensitivity)} data: ${dataTypes.map(fmtType).join(', ')}`;
        tdContext.appendChild(data);
      } else if (sensitivity !== 'unknown') {
        const sens = document.createElement('span');
        sens.className = 'evidence';
        sens.textContent = `Sensitivity: ${cap(sensitivity)}`;
        tdContext.appendChild(sens);
      }
      const rawCode = node.code || '';
      const snippet = rawCode.length > CONFIG.snippetLen ? rawCode.substring(0, CONFIG.snippetLen) + '...' : rawCode;
      const snip = document.createElement('span');
      snip.className = 'evidence';
      snip.textContent = snippet;
      tdContext.appendChild(snip);

      // Location
      const tdLoc = document.createElement('td');
      const loc = document.createElement('span');
      loc.style.color = CONFIG.locationColor;
      loc.textContent = `${node.file || ''}${node.line > 0 ? ' : L' + node.line : ''}`;
      tdLoc.appendChild(loc);
      tr.appendChild(tdType);
      tr.appendChild(tdName);
      tr.appendChild(tdContext);
      tr.appendChild(tdLoc);
      tbody.appendChild(tr);
    });
  });
});

